SELECT Min(oMonetaryAmount.`HASAMOUNT`) AS AggResult1, oListedSecurity.`HASTICKERSYMBOL` AS oListedSecurity_hasTickerSymbol, oListedSecurity.`HASLEGALNAME` AS oListedSecurity_hasLegalName FROM FIBEN.`LISTEDSECURITY` oListedSecurity INNER JOIN FIBEN.`MONETARYAMOUNT` oMonetaryAmount ON oListedSecurity.`HASLASTTRADEDVALUE`=oMonetaryAmount.`MONETARYAMOUNTID` GROUP BY oListedSecurity.`HASTICKERSYMBOL`,oListedSecurity.`HASLEGALNAME`
